# Error Handling Refactor вҖ” Phase 3

## Preliminary Review: Prior Decisions

Before writing a line of code, I'm auditing every constraint that error handling must satisfy.

| Source | Requirement | Impact on Error Handling |
|--------|-------------|--------------------------|
| ADR-003 | RFC 9457 Problem Details format, `application/problem+json` | Every error response shape |
| ADR-002 | 429 responses MUST include `Retry-After` | Rate limit error handler |
| ADR-001 | RS256 only; HS256 tokens must be rejected | Auth error classification |
| SEC-2025-041 | HS256 rejection is a compliance requirement | 401 error must not leak algorithm details |
| SEC-2025-044 | No stack traces, internal names, or DB errors in production | Error sanitization layer |
| Partner SLA | `Retry-After` is contractual on 429 | Cannot be optional |
| Integration Guide | Stripe webhook secret stays server-side | Webhook error handler must not echo secrets |

---

## Design

### 1. Error Type Registry

All `type` URIs must be dereferenceable per RFC 9457. I'm defining the full registry upfront so every handler references a canonical constant вҖ” no ad-hoc strings.

```typescript
// src/errors/errorTypes.ts

const BASE = 'https://api.payments.example/errors';

export const ErrorType = {
  // 400
  VALIDATION_FAILED:        `${BASE}/validation-failed`,
  INVALID_IDEMPOTENCY_KEY:  `${BASE}/invalid-idempotency-key`,
  INVALID_PAYMENT_METHOD:   `${BASE}/invalid-payment-method`,

  // 401
  AUTHENTICATION_REQUIRED:  `${BASE}/authentication-required`,
  TOKEN_EXPIRED:            `${BASE}/token-expired`,
  TOKEN_INVALID:            `${BASE}/token-invalid`,

  // 403
  PERMISSION_DENIED:        `${BASE}/permission-denied`,
  TENANT_MISMATCH:          `${BASE}/tenant-mismatch`,

  // 402
  INSUFFICIENT_FUNDS:       `${BASE}/insufficient-funds`,
  CARD_DECLINED:            `${BASE}/card-declined`,

  // 404
  RESOURCE_NOT_FOUND:       `${BASE}/resource-not-found`,

  // 409
  IDEMPOTENCY_CONFLICT:     `${BASE}/idempotency-conflict`,

  // 422
  UNPROCESSABLE_PAYMENT:    `${BASE}/unprocessable-payment`,

  // 429
  RATE_LIMITED:             `${BASE}/rate-limited`,

  // 502
  GATEWAY_ERROR:            `${BASE}/gateway-error`,

  // 500
  INTERNAL_ERROR:           `${BASE}/internal-error`,
} as const;

export type ErrorTypeValue = typeof ErrorType[keyof typeof ErrorType];
```

---

### 2. Domain Error Classes

Typed errors carry structured data through the call stack. The global handler reads this data вҖ” nothing is inferred from message strings.

```typescript
// src/errors/AppError.ts

import { ErrorTypeValue } from './errorTypes';

export interface ValidationErrorDetail {
  field: string;
  message: string;
  rejected_value?: unknown;
}

export interface ProblemDetails {
  type: ErrorTypeValue;
  title: string;
  status: number;
  detail: string;
  instance?: string;
  // Extension fields (RFC 9457 В§3.2 вҖ” MUST be namespaced)
  trace_id?: string;
  validation_errors?: ValidationErrorDetail[];
  retry_after?: number;           // seconds; mirrors Retry-After header
  idempotency_key?: string;
}

export class AppError extends Error {
  public readonly type: ErrorTypeValue;
  public readonly status: number;
  public readonly title: string;
  public readonly detail: string;
  public readonly extensions: Partial<ProblemDetails>;
  public readonly isOperational: boolean; // false = programmer error вҶ’ 500

  constructor(
    type: ErrorTypeValue,
    status: number,
    title: string,
    detail: string,
    extensions: Partial<ProblemDetails> = {},
    isOperational = true,
  ) {
    super(detail);
    this.type = type;
    this.status = status;
    this.title = title;
    this.detail = detail;
    this.extensions = extensions;
    this.isOperational = isOperational;
    Object.setPrototypeOf(this, new.target.prototype); // restore prototype chain
  }
}

// в”Җв”Җ Concrete subclasses в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

export class ValidationError extends AppError {
  constructor(detail: string, errors: ValidationErrorDetail[]) {
    super(
      ErrorType.VALIDATION_FAILED,
      400,
      'Validation Failed',
      detail,
      { validation_errors: errors },
    );
  }
}

export class AuthenticationError extends AppError {
  /**
   * Use this for 401: the request lacks valid credentials.
   * Do NOT reveal whether the token was HS256-signed, what the
   * signing secret is, or any internal algorithm detail.
   */
  constructor(
    type: typeof ErrorType.AUTHENTICATION_REQUIRED
        | typeof ErrorType.TOKEN_EXPIRED
        | typeof ErrorType.TOKEN_INVALID,
    detail: string,
  ) {
    const titles: Record<string, string> = {
      [ErrorType.AUTHENTICATION_REQUIRED]: 'Authentication Required',
      [ErrorType.TOKEN_EXPIRED]:           'Token Expired',
      [ErrorType.TOKEN_INVALID]:           'Invalid Token',
    };
    super(type, 401, titles[type], detail);
  }
}

export class PermissionError extends AppError {
  /**
   * Use this for 403: credentials are valid but access is denied.
   * 401 vs 403 distinction is critical вҖ” see design notes below.
   */
  constructor(detail: string, type = ErrorType.PERMISSION_DENIED) {
    super(type, 403, 'Permission Denied', detail);
  }
}

export class RateLimitError extends AppError {
  public readonly retryAfterSeconds: number;

  /**
   * retryAfterSeconds is REQUIRED вҖ” it drives the Retry-After header.
   * This is a contractual obligation (partner SLA, ADR-002).
   * The constructor enforces it at the type level: there is no
   * overload that omits it.
   */
  constructor(retryAfterSeconds: number, detail?: string) {
    super(
      ErrorType.RATE_LIMITED,
      429,
      'Too Many Requests',
      detail ?? `Rate limit exceeded. Retry after ${retryAfterSeconds} seconds.`,
      { retry_after: retryAfterSeconds },
    );
    this.retryAfterSeconds = retryAfterSeconds;
  }
}

export class NotFoundError extends AppError {
  constructor(resource: string, id: string) {
    super(
      ErrorType.RESOURCE_NOT_FOUND,
      404,
      'Resource Not Found',
      `${resource} '${id}' does not exist or you do not have access to it.`,
    );
  }
}

export class IdempotencyConflictError extends AppError {
  constructor(key: string) {
    super(
      ErrorType.IDEMPOTENCY_CONFLICT,
      409,
      'Idempotency Conflict',
      `A request with idempotency key '${key}' is already in progress.`,
      { idempotency_key: key },
    );
  }
}

export class GatewayError extends AppError {
  constructor(detail: string) {
    super(ErrorType.GATEWAY_ERROR, 502, 'Payment Gateway Error', detail);
  }
}
```

---

### 3. Auth Error Classification (401 vs 403)

This is the most nuanced part. The distinction matters both semantically and for security.

```typescript
// src/middleware/authErrorClassifier.ts

/**
 * 401 AUTHENTICATION_REQUIRED / TOKEN_INVALID / TOKEN_EXPIRED
 *   вҶ’ The request did not supply valid credentials.
 *   вҶ’ Client should re-authenticate.
 *   вҶ’ WWW-Authenticate header MUST be present (RFC 9110 В§11.6.1).
 *
 * 403 PERMISSION_DENIED
 *   вҶ’ Credentials are valid; the identity lacks the required permission.
 *   вҶ’ Client should NOT retry with the same token.
 *   вҶ’ No WWW-Authenticate header.
 *
 * SECURITY NOTE (SEC-2025-041):
 *   If token verification fails because the algorithm is HS256,
 *   we return TOKEN_INVALID вҖ” we do NOT say "wrong algorithm" in the
 *   detail field. Leaking that information would confirm to an attacker
 *   that HS256 tokens are being attempted and might reveal implementation
 *   details. The internal log captures the real reason.
 */

import { Request, Response, NextFunction } from 'express';
import { JwtPayload, verify, JsonWebTokenError, TokenExpiredError } from 'jsonwebtoken';
import { JwksClient } from 'jwks-rsa';
import { AuthenticationError, PermissionError } from '../errors/AppError';
import { ErrorType } from '../errors/errorTypes';
import logger from '../lib/logger';

const jwksClient = new JwksClient({
  jwksUri: process.env.JWKS_URI!, // e.g. https://auth.payments.example/.well-known/jwks.json
  cache: true,
  cacheMaxEntries: 5,
  cacheMaxAge: 600_000, // 10 minutes
});

function getSigningKey(header: { kid?: string }, callback: Function) {
  jwksClient.getSigningKey(header.kid, (err, key) => {
    if (err) return callback(err);
    callback(null, key?.getPublicKey());
  });
}

export async function requireAuth(
  req: Request,
  res: Response,
  next: NextFunction,
): Promise<void> {
  const authHeader = req.headers.authorization;

  if (!authHeader?.startsWith('Bearer ')) {
    return next(new AuthenticationError(
      ErrorType.AUTHENTICATION_REQUIRED,
      'This endpoint requires a Bearer token.',
    ));
  }

  const token = authHeader.slice(7);

  try {
    const payload = await new Promise<JwtPayload>((resolve, reject) => {
      verify(
        token,
        getSigningKey,
        {
          algorithms: ['RS256'], // HS256 is NEVER in this list вҖ” SEC-2025-041
          audience: 'payments-api',
          issuer: 'payments-auth',
        },
        (err, decoded) => {
          if (err) reject(err);
          else resolve(decoded as JwtPayload);
        },
      );
    });

    req.user = payload; // attach to request for downstream handlers
    next();

  } catch (err) {
    // Log the real reason internally вҖ” never surface it in the response
    logger.warn('Token validation failed', {
      reason: err instanceof Error ? err.message : String(err),
      // Do NOT log the token itself
    });

    if (err instanceof TokenExpiredError) {
      return next(new AuthenticationError(
        ErrorType.TOKEN_EXPIRED,
        'The access token has expired. Please refresh your token.',
      ));
    }

    // Covers: JsonWebTokenError (bad signature, wrong algorithm, malformed)
    // We intentionally give the same generic message for all of these
    // to avoid leaking algorithm/implementation details.
    return next(new AuthenticationError(
      ErrorType.TOKEN_INVALID,
      'The provided token is invalid.',
    ));
  }
}

export function requirePermission(permission: string) {
  return (req: Request, res: Response, next: NextFunction) => {
    const permissions: string[] = req.user?.permissions ?? [];

    if (!permissions.includes(permission)) {
      // 403, not 401 вҖ” the user IS authenticated, just not authorized
      return next(new PermissionError(
        `This action requires the '${permission}' permission.`,
      ));
    }

    next();
  };
}
```

---

### 4. Rate Limit Error Integration

The rate limiter (Phase 2) must hand off a `RateLimitError` with `retryAfterSeconds` populated. The global handler then sets the header. This is belt-and-suspenders: the header is set in two places so neither can be omitted independently.

```typescript
// src/middleware/rateLimiter.ts  (relevant excerpt вҖ” showing error throw)

import { RateLimitError } from '../errors/AppError';

// Inside the sliding window check:
if (effectiveCount > limit) {
  const windowResetAt = currentWindowStart + windowSizeSeconds;
  const retryAfter = Math.ceil(windowResetAt - (Date.now() / 1000));

  // RateLimitError constructor REQUIRES retryAfterSeconds вҖ” enforced by type
  throw new RateLimitError(
    Math.max(retryAfter, 1), // floor at 1 second вҖ” never send 0 or negative
    `You have exceeded the ${limit} requests/minute limit for your tier.`,
  );
}
```

---

### 5. Global Error Handler

This is the single place where all errors become HTTP responses. It is the only place that writes `application/problem+json`.

```typescript
// src/middleware/errorHandler.ts

import { Request, Response, NextFunction } from 'express';
import { v4 as uuidv4 } from 'uuid';
import { AppError, RateLimitError } from '../errors/AppError';
import { ErrorType } from '../errors/errorTypes';
import { ProblemDetails } from '../errors/AppError';
import logger from '../lib/logger';

const IS_PRODUCTION = process.env.NODE_ENV === 'production';

export function globalErrorHandler(
  err: unknown,
  req: Request,
  res: Response,
  next: NextFunction, // must be declared even if unused вҖ” Express requires 4-arg signature
): void {
  const traceId = (req.headers['x-trace-id'] as string) ?? uuidv4();

  // в”Җв”Җ Classify the error в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

  let problem: ProblemDetails;

  if (err instanceof AppError) {
    problem = {
      type:    err.type,
      title:   err.title,
      status:  err.status,
      detail:  err.detail,
      instance: req.path,
      trace_id: traceId,
      ...err.extensions,
    };
  } else {
    // Unknown/programmer error вҖ” log full details, return generic 500
    logger.error('Unhandled error', {
      trace_id: traceId,
      error: err instanceof Error ? {
        message: err.message,
        stack: err.stack,    // logged internally, NEVER sent to client
        name: err.name,
      } : String(err),
      path: req.path,
      method: req.method,
    });

    problem = {
      type:     ErrorType.INTERNAL_ERROR,
      title:    'Internal Server Error',
      status:   500,
      detail:   'An unexpected error occurred. Please try again or contact support.',
      instance: req.path,
      trace_id: traceId,
    };
  }

  // в”Җв”Җ Log operational errors at appropriate level в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

  if (err instanceof AppError) {
    const level = problem.status >= 500 ? 'error'
                : problem.status >= 400 ? 'warn'
                : 'info';

    logger[level]('Request error', {
      trace_id: traceId,
      type:     problem.type,
      status:   problem.status,
      path:     req.path,
      method:   req.method,
      // For non-500s, log the detail; for 500s we already logged above
      detail:   problem.detail,
    });
  }

  // в”Җв”Җ Set headers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

  // RFC 9457 content type вҖ” required on ALL error responses
  res.setHeader('Content-Type', 'application/problem
